solution_code:
#include <iostream>

int main() {
    int n{};
    std::cin >> n;

    int data[10]{};
    for (int i = 0; i < n; ++i) {
        std::cin >> data[i];
    }

    int maxVal = data[0];
    int* end = data + n;
    for (int* p = data + 1; p != end; ++p) {
        if (*p > maxVal)
            maxVal = *p;
    }

    std::cout << "Max: " << maxVal << '\n';
    return 0;
}

