#include <iostream>

int main() {
    int n{};
    std::cin >> n;

    int data[10]{};
    for (int i = 0; i < n; ++i) {
        std::cin >> data[i];
    }

    int sum = 0;
    int* end = data + n;
    for (int* p = data; p < end; p += 2) {
        sum += *p;
    }

    std::cout << "Even-index sum: " << sum << '\n';
    return 0;
}
